snippets.C0016:
// Caso: Top-K frecuentes | Nivel: Intermedio | Categoría: Map/Hash

import "sort"
type kv struct { k string; v int }
func Solve(arr []string, k int) []string {
  freq := map[string]int{}
  for _, x := range arr { freq[x]++ }
  list := make([]kv, 0, len(freq))
  for key, v := range freq { list = append(list, kv{key,v}) }
  sort.Slice(list, func(i,j int) bool { return list[i].v > list[j].v })
  if k > len(list) { k = len(list) }
  out := make([]string, 0, k)
  for i:=0;i<k;i++ { out = append(out, list[i].k) }
  return out
}

