func Solve(arr []int, target int) ([]int, bool) {
  seen := map[int]int{}
  for i, x := range arr {
    need := target - x
    if j, ok := seen[need]; ok { return []int{j, i}, true }
    seen[x] = i
  }
  return nil, false
}

