import "unicode"

func Solve(s string) bool {
  r := []rune{}
  for _, ch := range []rune(s) {
    if unicode.IsLetter(ch) || unicode.IsDigit(ch) {
      r = append(r, unicode.ToLower(ch))
    }
  }
  for i, j := 0, len(r)-1; i < j; i, j = i+1, j-1 {
    if r[i] != r[j] { return false }
  }
  return true
}

