import (
  "strings"
  "unicode"
)
func Solve(s string) string {
  fields := strings.Fields(strings.ToLower(s))
  for i, w := range fields {
    r := []rune(w)
    if len(r) > 0 {
      r[0] = unicode.ToUpper(r[0])
      fields[i] = string(r)
    }
  }
  return strings.Join(fields, " ")
}

