import "fmt"
func Solve(n int) []string {
  out := make([]string, 0, n)
  for i:=1; i<=n; i++ {
    s := ""
    if i%3==0 { s += "Fizz" }
    if i%5==0 { s += "Buzz" }
    if s=="" { s = fmt.Sprint(i) }
    out = append(out, s)
  }
  return out
}

