// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
package main

import (
  "strings"
  "unicode"
)

func Solve(rut string) bool {
  clean := strings.ToUpper(strings.NewReplacer(".", "", "-", "", " ", "").Replace(rut))
  if len(clean) < 2 { return false }

  body := clean[:len(clean)-1]
  dv := clean[len(clean)-1:]

  for _, ch := range body {
    if !unicode.IsDigit(ch) { return false }
  }

  sum := 0
  mul := 2
  for i := len(body)-1; i >= 0; i-- {
    d := int(body[i]-'0')
    sum += d * mul
    if mul == 7 { mul = 2 } else { mul++ }
  }

  mod := 11 - (sum % 11)
  dvCalc := ""
  if mod == 11 { dvCalc = "0" } else if mod == 10 { dvCalc = "K" } else { dvCalc = string('0' + byte(mod)) }
  return dv == dvCalc
}

