// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
// Go · stdlib encoding/csv
package main

import (
  "encoding/csv"
  "os"
  "strings"
)

func Solve(inputPath, outputPath string) error {
  in, err := os.Open(inputPath)
  if err != nil { return err }
  defer in.Close()
  r := csv.NewReader(in)
  header, err := r.Read()
  if err != nil { return err }

  out, err := os.Create(outputPath)
  if err != nil { return err }
  defer out.Close()
  w := csv.NewWriter(out)
  defer w.Flush()
  _ = w.Write(header)

  emailIdx := -1
  for i,h := range header {
    if strings.EqualFold(h,"Email") { emailIdx = i }
  }
  for {
    row, err := r.Read()
    if err != nil { break }
    if emailIdx >= 0 && emailIdx < len(row) {
      row[emailIdx] = strings.ToLower(strings.TrimSpace(row[emailIdx]))
    }
    _ = w.Write(row)
  }
  return w.Error()
}

