package main

import (
  "bytes"
  "context"
  "io"
  "net/http"
  "time"
)

func Solve(baseURL string) (string, string, error) {
  ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
  defer cancel()

  req1, _ := http.NewRequestWithContext(ctx, "GET", baseURL+"/api/items", nil)
  res1, err := http.DefaultClient.Do(req1)
  if err != nil { return "", "", err }
  b1, _ := io.ReadAll(res1.Body); res1.Body.Close()

  body := bytes.NewBufferString(`{"name":"Item","qty":1}`)
  req2, _ := http.NewRequestWithContext(ctx, "POST", baseURL+"/api/items", body)
  req2.Header.Set("Content-Type","application/json")
  res2, err := http.DefaultClient.Do(req2)
  if err != nil { return "", "", err }
  b2, _ := io.ReadAll(res2.Body); res2.Body.Close()

  return string(b1), string(b2), nil
}

