// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
package main
type Graph map[string][]string

func BFS(g Graph, start string) []string {
  q := []string{start}
  seen := map[string]bool{start:true}
  out := []string{}
  for len(q)>0 {
    v := q[0]; q = q[1:]
    out = append(out, v)
    for _, n := range g[v] {
      if !seen[n] { seen[n]=true; q = append(q, n) }
    }
  }
  return out
}

func DFS(g Graph, start string) []string {
  seen := map[string]bool{}
  out := []string{}
  var visit func(string)
  visit = func(v string){
    seen[v]=true; out=append(out,v)
    for _, n := range g[v] {
      if !seen[n] { visit(n) }
    }
  }
  visit(start)
  return out
}

snippets.C0669:
// C0669 · LRU cache (Intermedio, Algoritmos)
package main
import "container/list"

type entry struct{ key string; val any }

type LRU struct{
  cap int
  ll *list.List
  m map[string]*list.Element
}

func NewLRU(cap int) *LRU {
  return &LRU{cap:cap, ll:list.New(), m:map[string]*list.Element{}}
}

func (l *LRU) Get(k string) (any, bool){
  if el, ok := l.m[k]; ok {
    l.ll.MoveToBack(el)
    return el.Value.(entry).val, true
  }
  return nil, false
}

func (l *LRU) Put(k string, v any){
  if el, ok := l.m[k]; ok {
    el.Value = entry{key:k, val:v}
    l.ll.MoveToBack(el)
    return
  }
  el := l.ll.PushBack(entry{key:k, val:v})
  l.m[k] = el
  if l.ll.Len() > l.cap {
    front := l.ll.Front()
    kv := front.Value.(entry)
    delete(l.m, kv.key)
    l.ll.Remove(front)
  }
}

